<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Snake</title>
<style>
  :root {
    --bg: #0d1117;
    --panel: #161b22;
    --accent: #39d353;
    --snake: #39d353;
    --snake-head: #7ee787;
    --food: #f85149;
    --grid: #21262d;
    --text: #c9d1d9;
  }
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    padding: 0;
    height: 100%;
    background: var(--bg);
    color: var(--text);
    font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
  }
  body {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 16px;
    user-select: none;
  }
  h1 {
    margin: 0;
    font-weight: 600;
    letter-spacing: 1px;
  }
  #wrap {
    background: var(--panel);
    padding: 20px;
    border-radius: 12px;
    box-shadow: 0 10px 30px rgba(0,0,0,0.5);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 14px;
  }
  #score {
    font-size: 20px;
    font-weight: 600;
  }
  #score b { color: var(--accent); }
  canvas {
    background: #010409;
    border: 1px solid var(--grid);
    border-radius: 6px;
    display: block;
  }
  .controls {
    display: flex;
    gap: 10px;
  }
  button {
    background: #21262d;
    color: var(--text);
    border: 1px solid #30363d;
    padding: 8px 16px;
    border-radius: 6px;
    font-size: 14px;
    cursor: pointer;
    transition: background .15s, border-color .15s;
  }
  button:hover { background: #30363d; border-color: #8b949e; }
  button:active { transform: translateY(1px); }
  .hint { font-size: 12px; opacity: .6; }
</style>
</head>
<body>
  <h1>SNAKE</h1>
  <div id="wrap">
    <div id="score">Score: <b>0</b></div>
    <canvas id="snake" width="400" height="400"></canvas>
    <div class="controls">
      <button id="start">Start</button>
      <button id="pause">Pause</button>
      <button id="reset">Reset</button>
    </div>
    <div class="hint">Use Arrow Keys to steer</div>
  </div>

<script>
(function () {
  const W = 20;            // cells across
  const H = 20;            // cells down
  const CELL = 20;         // px per cell -> 400x400 canvas
  const canvas = document.getElementById('snake');
  const ctx = canvas.getContext('2d');
  const scoreEl = document.querySelector('#score b');

  let snake = [];          // array of [x,y], head first
  let dir = 'right';
  let nextDir = 'right';
  let foodPos = [0, 0];
  let isAlive = true;
  let sc = 0;
  let timer = null;
  const TICK_MS = 120;

  function opposite(a, b) {
    return (a === 'up' && b === 'down') ||
           (a === 'down' && b === 'up') ||
           (a === 'left' && b === 'right') ||
           (a === 'right' && b === 'left');
  }

  function placeFoodRandom() {
    const free = [];
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (!snake.some(s => s[0] === x && s[1] === y)) free.push([x, y]);
      }
    }
    if (free.length === 0) return;
    foodPos = free[Math.floor(Math.random() * free.length)];
  }

  function reset() {
    snake = [
      [Math.floor(W / 2) - 1, Math.floor(H / 2)],
      [Math.floor(W / 2) - 2, Math.floor(H / 2)],
      [Math.floor(W / 2) - 3, Math.floor(H / 2)]
    ];
    dir = 'right';
    nextDir = 'right';
    isAlive = true;
    sc = 0;
    scoreEl.textContent = '0';
    placeFoodRandom();
    draw();
  }

  function step() {
    if (!isAlive) return;
    if (!opposite(nextDir, dir)) dir = nextDir;

    const head = snake[0];
    let nx = head[0], ny = head[1];
    if (dir === 'up') ny--;
    else if (dir === 'down') ny++;
    else if (dir === 'left') nx--;
    else if (dir === 'right') nx++;

    // wall collision
    if (nx < 0 || ny < 0 || nx >= W || ny >= H) {
      isAlive = false;
      draw();
      stopLoop();
      return;
    }
    // self collision (exclude tail because it moves)
    for (let i = 0; i < snake.length - 1; i++) {
      if (snake[i][0] === nx && snake[i][1] === ny) {
        isAlive = false;
        draw();
        stopLoop();
        return;
      }
    }

    snake.unshift([nx, ny]);
    if (nx === foodPos[0] && ny === foodPos[1]) {
      sc++;
      scoreEl.textContent = String(sc);
      placeFoodRandom();
    } else {
      snake.pop();
    }
    draw();
  }

  function draw() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    // grid
    ctx.strokeStyle = '#21262d';
    ctx.lineWidth = 1;
    for (let i = 0; i <= W; i++) {
      ctx.beginPath();
      ctx.moveTo(i * CELL + 0.5, 0);
      ctx.lineTo(i * CELL + 0.5, H * CELL);
      ctx.stroke();
    }
    for (let j = 0; j <= H; j++) {
      ctx.beginPath();
      ctx.moveTo(0, j * CELL + 0.5);
      ctx.lineTo(W * CELL, j * CELL + 0.5);
      ctx.stroke();
    }
    // food
    ctx.fillStyle = '#f85149';
    ctx.beginPath();
    ctx.arc(foodPos[0] * CELL + CELL / 2, foodPos[1] * CELL + CELL / 2, CELL / 2 - 2, 0, Math.PI * 2);
    ctx.fill();
    // snake
    for (let i = snake.length - 1; i >= 0; i--) {
      const [x, y] = snake[i];
      ctx.fillStyle = i === 0 ? '#7ee787' : '#39d353';
      ctx.fillRect(x * CELL + 1, y * CELL + 1, CELL - 2, CELL - 2);
    }
    if (!isAlive) {
      ctx.fillStyle = 'rgba(248,81,73,0.85)';
      ctx.font = 'bold 28px system-ui';
      ctx.textAlign = 'center';
      ctx.fillText('GAME OVER', canvas.width / 2, canvas.height / 2);
    }
  }

  function startLoop() {
    if (timer) return;
    timer = setInterval(() => step(), TICK_MS);
  }
  function stopLoop() {
    if (timer) { clearInterval(timer); timer = null; }
  }

  document.getElementById('start').addEventListener('click', () => {
    if (isAlive) startLoop();
  });
  document.getElementById('pause').addEventListener('click', stopLoop);
  document.getElementById('reset').addEventListener('click', () => {
    stopLoop();
    reset();
  });

  window.addEventListener('keydown', (e) => {
    const map = {
      ArrowUp: 'up', ArrowDown: 'down', ArrowLeft: 'left', ArrowRight: 'right'
    };
    if (map[e.key]) {
      e.preventDefault();
      window.game.setDir(map[e.key]);
    }
  });

  // Public API
  window.game = {
    w: W,
    h: H,
    reset: reset,
    tick: step,
    setDir: function (d) {
      if (['up', 'down', 'left', 'right'].includes(d) && !opposite(d, dir)) {
        nextDir = d;
      }
    },
    setFood: function (x, y) {
      foodPos = [x, y];
      draw();
    },
    snake: function () { return snake.map(s => [s[0], s[1]]); },
    food: function () { return [foodPos[0], foodPos[1]]; },
    alive: function () { return isAlive; },
    score: function () { return sc; }
  };

  reset();
})();
</script>
</body>
</html>
